import{_ as a,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Inicialización: Proyecto | opencode-supermemory","description":"Aprende a usar /supermemory-init para explorar el repositorio, extraer arquitectura y normas, almacenándolas en memoria persistente.","frontmatter":{"title":"Inicialización: Proyecto | opencode-supermemory","sidebarTitle":"Inicialización","subtitle":"Inicialización del Proyecto: Creando la Primera Impresión","description":"Aprende a usar /supermemory-init para explorar el repositorio, extraer arquitectura y normas, almacenándolas en memoria persistente.","tags":["inicialización","generación de memoria","flujo de trabajo"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"es/supermemoryai/opencode-supermemory/start/initialization/index.md","filePath":"es/supermemoryai/opencode-supermemory/start/initialization/index.md"}'),r={name:"es/supermemoryai/opencode-supermemory/start/initialization/index.md"};function n(s,e,c,l,d,p){return i(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="inicializacion-del-proyecto-creando-la-primera-impresion" tabindex="-1">Inicialización del Proyecto: Creando la Primera Impresión <a class="header-anchor" href="#inicializacion-del-proyecto-creando-la-primera-impresion" aria-label="Permalink to &quot;Inicialización del Proyecto: Creando la Primera Impresión&quot;">​</a></h1><h2 id="lo-que-podras-hacer-al-terminar" tabindex="-1">Lo que podrás hacer al terminar <a class="header-anchor" href="#lo-que-podras-hacer-al-terminar" aria-label="Permalink to &quot;Lo que podrás hacer al terminar&quot;">​</a></h2><ul><li><strong>Familiarizarse con el proyecto en un solo paso</strong>: Haz que el Agent explore y comprenda todo el repositorio de código activamente, como un nuevo empleado que se une.</li><li><strong>Establecer memoria a largo plazo</strong>: Extrae automáticamente el stack tecnológico, patrones de arquitectura y normas de codificación del proyecto, y almacénalos en Supermemory.</li><li><strong>Eliminar explicaciones repetidas</strong>: Nunca más necesites repetir &quot;usamos Bun&quot; o &quot;todos los componentes deben tener pruebas&quot; al comienzo de cada sesión.</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>¿Alguna vez te has encontrado con estas situaciones:</p><ul><li><strong>Trabajo repetitivo</strong>: Cada vez que inicias una nueva sesión, gastas mucho tiempo explicando al Agent la situación básica del proyecto.</li><li><strong>Olvido del contexto</strong>: El Agent frecuentemente olvida la estructura de directorios específica del proyecto, creando archivos en la ubicación incorrecta.</li><li><strong>Normas inconsistentes</strong>: El estilo de código escrito por el Agent es errático, a veces usando <code>interface</code> y otras veces <code>type</code>.</li></ul><h2 id="cuando-usar-este-metodo" tabindex="-1">Cuándo usar este método <a class="header-anchor" href="#cuando-usar-este-metodo" aria-label="Permalink to &quot;Cuándo usar este método&quot;">​</a></h2><ul><li><strong>Después de instalar el plugin</strong>: Este es el primer paso para usar opencode-supermemory.</li><li><strong>Al hacerse cargo de un nuevo proyecto</strong>: Establece rápidamente la biblioteca de memoria de ese proyecto.</li><li><strong>Después de una refactorización mayor</strong>: Cuando la arquitectura del proyecto cambia, necesitas actualizar el conocimiento del Agent.</li></ul><h2 id="🎒-preparacion-previa" tabindex="-1">🎒 Preparación previa <a class="header-anchor" href="#🎒-preparacion-previa" aria-label="Permalink to &quot;🎒 Preparación previa&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Verificación previa</p><p>Asegúrate de haber completado los pasos de instalación y configuración en <a href="./../getting-started/">Inicio Rápido</a> y que <code>SUPERMEMORY_API_KEY</code> esté correctamente configurado.</p></div><h2 id="idea-central" tabindex="-1">Idea Central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea Central&quot;">​</a></h2><p>El comando <code>/supermemory-init</code> esencialmente no es un programa binario, sino un <strong>Prompt cuidadosamente diseñado</strong>.</p><p>Cuando ejecutas este comando, envía al Agent una &quot;guía de incorporación&quot; detallada, indicando al Agent:</p><ol><li><strong>Investigación profunda</strong>: Leer activamente <code>README.md</code>, <code>package.json</code>, registros de commits de Git, etc.</li><li><strong>Análisis estructurado</strong>: Identificar el stack tecnológico, patrones de arquitectura y convenciones implícitas del proyecto.</li><li><strong>Almacenamiento persistente</strong>: Usar la herramienta <code>supermemory</code> para almacenar estas percepciones en la base de datos en la nube.</li></ol><div class="info custom-block"><p class="custom-block-title">Alcance de la memoria</p><p>El proceso de inicialización distinguirá entre dos tipos de memoria:</p><ul><li><strong>Project Scope</strong>: Solo efectivo para el proyecto actual (ej: comando de compilación, estructura de directorios).</li><li><strong>User Scope</strong>: Efectivo para todos tus proyectos (ej: tu estilo de codificación preferido).</li></ul></div><h2 id="sigueme" tabindex="-1">Sígueme <a class="header-anchor" href="#sigueme" aria-label="Permalink to &quot;Sígueme&quot;">​</a></h2><h3 id="paso-1-ejecutar-el-comando-de-inicializacion" tabindex="-1">Paso 1: Ejecutar el comando de inicialización <a class="header-anchor" href="#paso-1-ejecutar-el-comando-de-inicializacion" aria-label="Permalink to &quot;Paso 1: Ejecutar el comando de inicialización&quot;">​</a></h3><p>En el cuadro de entrada de OpenCode, escribe el siguiente comando y envíalo:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/supermemory-init</span></span></code></pre></div><p><strong>Por qué</strong> Esto carga el Prompt predefinido, iniciando el modo de exploración del Agent.</p><p><strong>Deberías ver</strong> El Agent comienza a responder, indicando que entiende la tarea y comienza a planear los pasos de investigación. Podría decir: &quot;I will start by exploring the codebase structure and configuration files...&quot;</p><h3 id="paso-2-observar-el-proceso-de-exploracion-del-agent" tabindex="-1">Paso 2: Observar el proceso de exploración del Agent <a class="header-anchor" href="#paso-2-observar-el-proceso-de-exploracion-del-agent" aria-label="Permalink to &quot;Paso 2: Observar el proceso de exploración del Agent&quot;">​</a></h3><p>El Agent ejecutará automáticamente una serie de operaciones, solo necesitas observar. Usualmente:</p><ol><li><strong>Leer archivos de configuración</strong>: Lee <code>package.json</code>, <code>tsconfig.json</code>, etc. para entender el stack tecnológico.</li><li><strong>Verificar historial de Git</strong>: Ejecuta <code>git log</code> para entender las convenciones de commit y contribuidores activos.</li><li><strong>Explorar estructura de directorios</strong>: Usa <code>ls</code> o <code>list_files</code> para ver el diseño del proyecto.</li></ol><p><strong>Ejemplo de salida</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Agent] Reading package.json to identify dependencies...</span></span>
<span class="line"><span>[Agent] Running git log to understand commit conventions...</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Nota de consumo</p><p>Este proceso es una investigación profunda y puede consumir muchos Tokens (usualmente hará 50+ llamadas a herramientas). Por favor sé paciente hasta que el Agent reporte la finalización.</p></div><h3 id="paso-3-verificar-la-memoria-generada" tabindex="-1">Paso 3: Verificar la memoria generada <a class="header-anchor" href="#paso-3-verificar-la-memoria-generada" aria-label="Permalink to &quot;Paso 3: Verificar la memoria generada&quot;">​</a></h3><p>Cuando el Agent indica que la inicialización está completa, puedes verificar qué recordó exactamente. Escribe:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Listar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memorias</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> del</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> proyecto</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> actual</span></span></code></pre></div><p>O llama directamente a la herramienta (si quieres ver los datos crudos):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>supermemory(mode: &quot;list&quot;, scope: &quot;project&quot;)</span></span></code></pre></div><p><strong>Deberías ver</strong> El Agent enumera una serie de memorias estructuradas, por ejemplo:</p><table tabindex="0"><thead><tr><th>Tipo</th><th>Ejemplo de contenido</th></tr></thead><tbody><tr><td><code>project-config</code></td><td>&quot;Uses Bun runtime. Build command: bun run build&quot;</td></tr><tr><td><code>architecture</code></td><td>&quot;API routes are located in src/routes/, using Hono framework&quot;</td></tr><tr><td><code>preference</code></td><td>&quot;Strict TypeScript usage: no &#39;any&#39; type allowed&quot;</td></tr></tbody></table><h3 id="paso-4-complementar-lo-que-falta-opcional" tabindex="-1">Paso 4: Complementar lo que falta (opcional) <a class="header-anchor" href="#paso-4-complementar-lo-que-falta-opcional" aria-label="Permalink to &quot;Paso 4: Complementar lo que falta (opcional)&quot;">​</a></h3><p>Si el Agent omitió cierta información clave (como alguna regla especial acordada solo verbalmente), puedes complementar manualmente:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Por favor recuerda: en este proyecto, todo el procesamiento de fechas debe usar la librería dayjs, está prohibido usar Date nativo.</span></span></code></pre></div><p><strong>Deberías ver</strong> El Agent responde confirmando y llama <code>supermemory(mode: &quot;add&quot;)</code> para guardar esta nueva regla.</p><h2 id="punto-de-control-✅" tabindex="-1">Punto de Control ✅ <a class="header-anchor" href="#punto-de-control-✅" aria-label="Permalink to &quot;Punto de Control ✅&quot;">​</a></h2><ul><li>[ ] Después de ejecutar <code>/supermemory-init</code>, ¿ejecutó el Agent automáticamente la tarea de exploración?</li><li>[ ] ¿Puedes ver las memorias recién generadas usando el comando <code>list</code>?</li><li>[ ] ¿El contenido de la memoria refleja con precisión la situación real del proyecto actual?</li></ul><h2 id="advertencias-de-errores-comunes" tabindex="-1">Advertencias de errores comunes <a class="header-anchor" href="#advertencias-de-errores-comunes" aria-label="Permalink to &quot;Advertencias de errores comunes&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">No ejecutes frecuentemente</p><p>La inicialización es un proceso que consume tiempo y Tokens. Usualmente cada proyecto solo necesita ejecutarse una vez. Solo necesita volver a ejecutarse cuando el proyecto sufre cambios masivos.</p></div><div class="danger custom-block"><p class="custom-block-title">Nota de privacidad</p><p>Aunque el plugin desensibilizará automáticamente el contenido de las etiquetas <code>&lt;private&gt;</code>, durante el proceso de inicialización, el Agent leerá muchos archivos. Asegúrate de que no haya claves sensibles codificadas en tu repositorio de código (como AWS Secret Key), de lo contrario podrían almacenarse como &quot;configuración del proyecto&quot; en la memoria.</p></div><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><p>A través de <code>/supermemory-init</code>, completamos la transición de &quot;desconocido&quot; a &quot;trabajador experto&quot;. Ahora, el Agent ya recuerda la arquitectura y normas principales del proyecto, y en las siguientes tareas de codificación, utilizará automáticamente este contexto para brindarte asistencia más precisa.</p><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la siguiente lección aprenderemos <strong><a href="./../../core/context-injection/">Mecanismo de Inyección Automática de Contexto</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo el Agent &quot;recuerda&quot; estas memorias al inicio de la sesión.</li><li>Cómo activar el recuerdo de memorias específicas mediante palabras clave.</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Clic para expandir y ver ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Número de línea</th></tr></thead><tbody><tr><td>Definición del Prompt de inicialización</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/cli.ts#L13-L163" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>13-163</td></tr><tr><td>Implementación de herramientas de memoria</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr></tbody></table><p><strong>Constantes clave</strong>:</p><ul><li><code>SUPERMEMORY_INIT_COMMAND</code>: Define el contenido específico del Prompt del comando <code>/supermemory-init</code>, guiando al Agent sobre cómo realizar la investigación y la memoria.</li></ul></details>`,50)])])}const g=a(r,[["render",n]]);export{m as __pageData,g as default};
